    connectionsN2.removeInEdge(edge);
    edgeToIncidentNodes.remove(edge);
  }

  private NodeConnections<N, E> newNodeConnections(boolean isDirected) {
    return isDirected
        ? DirectedNodeConnections.<N, E>of()
        : UndirectedNodeConnections.<N, E>of();
  }
}

