  public static <N, E> ImmutableGraph<N, E> copyOf(Graph<N, E> graph) {
    return (graph instanceof ImmutableGraph)
        ? (ImmutableGraph<N, E>) graph
        : new ImmutableGraph<N, E>(graph);
